import{_ as r,c as t,o as a,ae as e}from"./chunks/framework.Cqi9LMMK.js";const p=JSON.parse('{"title":"Релиз 2.2.0","description":"","frontmatter":{"title":"Релиз 2.2.0"},"headers":[],"relativePath":"releases/2.2.0.md","filePath":"releases/2.2.0.md"}'),l={name:"releases/2.2.0.md"};function i(n,o,s,g,h,u){return a(),t("div",null,[...o[0]||(o[0]=[e('<h2 id="_2-2-0-2026-02-24" tabindex="-1">[2.2.0] - 2026-02-24 <a class="header-anchor" href="#_2-2-0-2026-02-24" aria-label="Permalink to &quot;[2.2.0] - 2026-02-24&quot;">​</a></h2><h3 id="общие-изменения" tabindex="-1">Общие изменения: <a class="header-anchor" href="#общие-изменения" aria-label="Permalink to &quot;Общие изменения:&quot;">​</a></h3><ul><li>Добавлена настройка <strong>Display Mode</strong> с возможностью переноса приложения во вкладку DevTools (отключение overlay-режима).</li><li>Проведён рефакторинг вкладки <strong>Options</strong> — настройки разбиты на логические разделы.</li><li>Изменена логика работы активных фильтров на вкладках <strong>Props</strong>, <strong>Pinia Store</strong> и <strong>Network</strong> — редактирование набора фильтров теперь доступно без перехода в настройки.</li><li>Исправлена область нажатия (click area) в текстовом режиме отображения JSON.</li><li>Большие JSON больше не обрезаются; для сохранения производительности при их отображении отключаются CSS-стили.</li><li>Обновлена логика уведомления о новых версиях: <ul><li><strong>Dismiss</strong> переименована в <strong>Later</strong>;</li><li><strong>Download</strong> переименована в <strong>Preview</strong> и ведёт в <strong>Options → About</strong>;</li><li>Добавлен блок с деталями версии и кнопками <strong>Ignore</strong> и <strong>Download</strong>.</li></ul></li></ul><h3 id="props" tabindex="-1">Props: <a class="header-anchor" href="#props" aria-label="Permalink to &quot;Props:&quot;">​</a></h3><ul><li>Исправлена ошибка отсутствия подсветки UI props в режиме Standalone.</li></ul><h3 id="network" tabindex="-1">Network: <a class="header-anchor" href="#network" aria-label="Permalink to &quot;Network:&quot;">​</a></h3><ul><li>Добавлена поддержка form-data для чтения и подмены трафика.</li><li>Добавлена возможность сохранить используемые файлы для повторного переиспользования при работе с Breakpoint с form-data.</li><li>Добавлены режимы <strong>Rewrite Breakpoint</strong> и <strong>Rewrite Mock</strong>. При наличии существующего перехвата предлагается перезаписать правило вместо создания нового.</li><li>Добавлена индикация активных <strong>Breakpoint</strong> и <strong>Mock</strong> для запроса; переход по счётчику открывает соответствующий раздел настроек.</li><li>Добавлен поиск по статус-коду ответа.</li><li>Расширены возможности <strong>Breakpoint</strong> — добавлен учёт HTTP-метода при перехвате.</li><li>Исправлена ошибка, при которой инспектор не открывался при срабатывании Breakpoint.</li><li>В контекстное меню запроса добавлены действия: <ul><li><strong>Disable / Enable Breakpoint</strong>;</li><li><strong>Disable / Enable Mock</strong>;</li><li><strong>Delete Breakpoint / Mock</strong>;</li><li>Пункты отображаются только при наличии соответствующего правила.</li></ul></li></ul><h3 id="options" tabindex="-1">Options: <a class="header-anchor" href="#options" aria-label="Permalink to &quot;Options:&quot;">​</a></h3><h4 id="general" tabindex="-1">General: <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General:&quot;">​</a></h4><ul><li>Базовые настройки приложения (<strong>Display Mode</strong>, <strong>Search Parameters</strong>, <strong>Auto Refresh</strong>, <strong>JSON Editor Mode</strong>) перенесены в отдельный раздел.</li><li>Управление файлом настроек (<strong>Settings Management</strong>) перенесено из шапки вкладки.</li></ul><h4 id="network-1" tabindex="-1">Network: <a class="header-anchor" href="#network-1" aria-label="Permalink to &quot;Network:&quot;">​</a></h4><ul><li><strong>Search Settings</strong> вынесены в отдельный раздел и стали независимыми.</li><li>Скорректирована вёрстка таблиц <strong>Breakpoints</strong> и <strong>Mocks</strong> — данные больше не растягиваются.</li><li>Добавлена возможность отключения и редактирования ранее созданных правил.</li></ul><h4 id="props-1" tabindex="-1">Props: <a class="header-anchor" href="#props-1" aria-label="Permalink to &quot;Props:&quot;">​</a></h4><ul><li>Управление файлом настроек перенесено в раздел.</li><li><strong>Component Blacklist</strong> перенесён из общего блока настроек.</li><li><strong>Favorite Components</strong> перенесены из общего блока настроек.</li></ul><h4 id="pinia-store" tabindex="-1">Pinia Store: <a class="header-anchor" href="#pinia-store" aria-label="Permalink to &quot;Pinia Store:&quot;">​</a></h4><ul><li>Управление файлом настроек перенесено в раздел.</li></ul><h4 id="about" tabindex="-1">About: <a class="header-anchor" href="#about" aria-label="Permalink to &quot;About:&quot;">​</a></h4><ul><li>Добавлены кнопки <strong>Release notes</strong> и <strong>Check for updates</strong> (доступна только в extension-версии).</li><li>При наличии новой версии: <ul><li><strong>Ignore</strong> отключает повторные уведомления для текущей версии (сбрасывается при выходе более новой версии);</li><li><strong>Download</strong> инициирует загрузку архива с приложением.</li></ul></li></ul>',18)])])}const c=r(l,[["render",i]]);export{p as __pageData,c as default};
